// Parse the booking details out of the calendar event created by the AI agent.
// Event description format (from the system prompt):
// Name: ..., Phone: ..., Business: ..., Requirement: ..., Budget: ..., Service Interested: ...
const ev = $input.first().json;

const summary = ev.summary || '';
const description = ev.description || '';
const text = summary + String.fromCharCode(10) + description;

// Only sync Nexora consultation events (skip personal calendar events)
if (!/nexora/i.test(summary)) {
  return []; // not a booking made by the agent - ignore
}

// Extract phone: first 10-15 digit sequence in the description
const phoneMatch = text.replace(/[\s+-]/g, '').match(/(91\d{10}|\d{10,14})/);
const phone = phoneMatch ? (phoneMatch[1].length === 10 ? '91' + phoneMatch[1] : phoneMatch[1]) : '';

// Extract name: from 'Name: X' in description, else from summary after the dash
let name = '';
const nameMatch = description.match(/name\s*[:\-]\s*([^\n,;|]+)/i);
if (nameMatch) name = nameMatch[1].trim();
if (!name) {
  const sumMatch = summary.match(/[-–]\s*(.+)$/);
  if (sumMatch) name = sumMatch[1].trim();
}
if (!name) name = 'WhatsApp Lead';

const startTime = ev.start?.dateTime || ev.start?.date || '';
const googleEventId = ev.id || '';

if (!phone || !startTime || !googleEventId) {
  return []; // not enough data to sync safely
}

return [{ json: {
  action: 'book',
  phone,
  name,
  startTime,
  googleEventId,
  notes: description.slice(0, 500)
} }];
